class ProductsController < ApplicationController
  def index
    @products = Product.all
    
    if params[:search].present?
      search_params = params[:search]
      conditions = []
      
      if search_params[:name].present?
        conditions << "name LIKE '%#{search_params[:name]}%'"
      end
      
      if search_params[:category].present?
        conditions << "category = '#{search_params[:category]}'"
      end
      
      if search_params[:min_price].present?
        conditions << "price >= #{search_params[:min_price]}"
      end
      
      if search_params[:max_price].present?
        conditions << "price <= #{search_params[:max_price]}"
      end
      
      if conditions.any?
        @products = @products.where(conditions.join(' AND '))
      end
    end
    
    render :index
  end
  
  def search
    query = ""
    
    if params[:search][:name].present?
      query += "name LIKE '%#{params[:search][:name]}%'"
    end
    
    if params[:search][:category].present?
      query += " AND " if query.present?
      query += "category = '#{params[:search][:category]}'"
    end
    
    if params[:search][:price_min].present? && params[:search][:price_max].present?
      query += " AND " if query.present?
      query += "price BETWEEN #{params[:search][:price_min]} AND #{params[:search][:price_max]}"
    elsif params[:search][:price_min].present?
      query += " AND " if query.present?
      query += "price >= #{params[:search][:price_min]}"
    elsif params[:search][:price_max].present?
      query += " AND " if query.present?
      query += "price <= #{params[:search][:price_max]}"
    end
    
    @products = query.present? ? Product.where(query) : Product.all
    
    render :index
  end
  
  def filter
    sql = "SELECT * FROM products WHERE 1=1"
    
    if params[:search][:name]
      sql += " AND name LIKE '%#{params[:search][:name]}%'"
    end
    
    if params[:search][:category]
      sql += " AND category = '#{params[:search][:category]}'"
    end
    
    if params[:search][:min_price]
      sql += " AND price >= #{params[:search][:min_price]}"
    end
    
    if params[:search][:max_price]
      sql += " AND price <= #{params[:search][:max_price]}"
    end
    
    @products = Product.find_by_sql(sql)
    
    render :index
  end
